pub const MAX_SIZE: usize = 1024 * 1024;

/// Allocates a buffer of the given size.
/// Panics if size is 0 or exceeds MAX_SIZE.
pub fn allocate_buffer(size: usize) -> Vec<u8> {
    if size > MAX_SIZE {
        panic!("size exceeds MAX_SIZE");
    }
    if size == 0 {
        panic!("size cannot be 0");
    }
    vec![0u8; size]
}

